# Write-CanonFiles3.ps1 — Creates D1.2 analysis scripts for all 3 specs
# Run from: C:\Users\whale\git\uiao\tools\
# Usage:    powershell -ExecutionPolicy Bypass -File .\Write-CanonFiles3.ps1

$ErrorActionPreference = "Stop"
$repoRoot = "C:\Users\whale\git\uiao"

if (-not (Test-Path $repoRoot)) {
    Write-Error "Repo root not found: $repoRoot"
    return
}

# --- Spec 1 D1.2 — Device State Classification Matrix ---
$b64_0 = ""
$target_0 = Join-Path $repoRoot "tools\discovery\Spec1-D1.2-ConvertTo-DeviceClassificationMatrix.ps1"
$dir_0 = Split-Path $target_0 -Parent
if (-not (Test-Path $dir_0)) { New-Item -Path $dir_0 -ItemType Directory -Force | Out-Null }
Write-Host "Writing Spec 1 D1.2 — Device State Classification Matrix..." -ForegroundColor Yellow
[System.IO.File]::WriteAllBytes($target_0, [Convert]::FromBase64String($b64_0))
Write-Host "  OK  $target_0" -ForegroundColor Green

# --- Spec 2 D1.2 — HR-to-OrgPath Translation Rules ---
$b64_1 = ""
$target_1 = Join-Path $repoRoot "tools\discovery\Spec2-D1.2-ConvertTo-OrgPathTranslationRules.ps1"
$dir_1 = Split-Path $target_1 -Parent
if (-not (Test-Path $dir_1)) { New-Item -Path $dir_1 -ItemType Directory -Force | Out-Null }
Write-Host "Writing Spec 2 D1.2 — HR-to-OrgPath Translation Rules..." -ForegroundColor Yellow
[System.IO.File]::WriteAllBytes($target_1, [Convert]::FromBase64String($b64_1))
Write-Host "  OK  $target_1" -ForegroundColor Green

# --- Spec 3 D1.2 — Scheduled Task Credential Audit ---
$b64_2 = ""
$target_2 = Join-Path $repoRoot "tools\discovery\Spec3-D1.2-Get-ScheduledTaskCredentialAudit.ps1"
$dir_2 = Split-Path $target_2 -Parent
if (-not (Test-Path $dir_2)) { New-Item -Path $dir_2 -ItemType Directory -Force | Out-Null }
Write-Host "Writing Spec 3 D1.2 — Scheduled Task Credential Audit..." -ForegroundColor Yellow
[System.IO.File]::WriteAllBytes($target_2, [Convert]::FromBase64String($b64_2))
Write-Host "  OK  $target_2" -ForegroundColor Green

Write-Host ""
Write-Host "All 3 D1.2 scripts written to tools\discovery\" -ForegroundColor Cyan
Write-Host ""
Write-Host "Commit with:" -ForegroundColor Cyan
Write-Host "  cd C:\Users\whale\git\uiao"
Write-Host "  git add tools/discovery/"
Write-Host '  git commit -m "feat(discovery): add D1.2 analysis scripts for all 3 specs'
Write-Host ''
Write-Host '  Spec 1 D1.2: Device State Classification Matrix'
Write-Host '    Consumes D1.1 JSON, classifies Active/Stale/Abandoned/Infrastructure-Critical,'
Write-Host '    scores migration readiness 0-100, assesses OS currency. CSV + JSON output.'
Write-Host '  Spec 2 D1.2: HR-to-OrgPath Translation Rules'
Write-Host '    Consumes D1.1 JSON, generates canonical OrgPath schema, translation rules,'
Write-Host '    department/division maps, data quality assessment. JSON + Markdown output.'
Write-Host '  Spec 3 D1.2: Scheduled Task Credential Audit'
Write-Host '    Scans local/remote servers, classifies credentials, cross-references D1.1'
Write-Host '    risk scores, recommends migration targets per ADR-004. JSON + CSV output.'
Write-Host ''
Write-Host '  Ref: UIAO_136, ADR-004, ADR-048"'
Write-Host "  git push origin main"
